/**
 * Handler 6: Smart Rule Suggestions (per-file, InstructionsLoaded)
 *
 * Accumulates the basenames of loaded instruction files in a session-scoped
 * state file, scans project signals (package.json, Dockerfile, workflows...),
 * and records which .claude/rules/ files are missing. Surfaces the suggestion
 * ONCE per session via systemMessage; every other firing is silent (state
 * file only — additionalContext is stripped for this event).
 */

import { logHook } from '../lib/common.js';
import { existsSync, readFileSync } from 'node:fs';
import { basename, join } from 'node:path';
import { atomicWriteSync } from '../lib/atomic-write.js';
import { getProjectDir, getSessionTempDir } from '../lib/paths.js';
import type { InstructionsLoadedInput } from '../types.js';
import type { LoadedInstructionsState, ProjectSignal } from './types.js';

const HOOK_NAME = 'instructions-loaded/smart-suggestions';

function getStatePath(sessionId: string): string {
  return join(getSessionTempDir(sessionId), 'loaded-instructions.json');
}

function loadState(statePath: string): LoadedInstructionsState {
  try {
    if (existsSync(statePath)) {
      const parsed = JSON.parse(readFileSync(statePath, 'utf8')) as LoadedInstructionsState;
      if (parsed && Array.isArray(parsed.files)) return parsed;
    }
  } catch {
    // Corrupted state — rebuild
  }
  return { version: '1.0', files: [], suggestions: [], notified: false };
}

function buildSignals(projectDir: string): ProjectSignal[] {
  return [
    {
      check: () => existsSync(join(projectDir, 'package.json')),
      ruleName: 'build-required.md',
      description: 'Has package.json but no build-required rule',
    },
    {
      check: () => existsSync(join(projectDir, '.github', 'workflows')),
      ruleName: 'ci-workflows.md',
      description: 'Has GitHub Actions workflows',
    },
    {
      check: () => existsSync(join(projectDir, 'Dockerfile')) || existsSync(join(projectDir, 'docker-compose.yml')),
      ruleName: 'docker-conventions.md',
      description: 'Has Docker config but no docker-conventions rule',
    },
    {
      check: () => existsSync(join(projectDir, 'tsconfig.json')),
      ruleName: 'typescript-conventions.md',
      description: 'Has TypeScript config but no TS conventions rule',
    },
    {
      check: () => {
        try {
          const pkg = JSON.parse(readFileSync(join(projectDir, 'package.json'), 'utf8'));
          return !!(pkg.dependencies?.next || pkg.devDependencies?.next);
        } catch { return false; }
      },
      ruleName: 'nextjs-conventions.md',
      description: 'Uses Next.js but no Next.js conventions rule',
    },
    {
      check: () => existsSync(join(projectDir, 'src', 'hooks')),
      ruleName: 'hot-path-hooks.md',
      description: 'Has hooks directory but no hot-path-hooks rule',
    },
  ];
}

export function smartRuleSuggestions(input: InstructionsLoadedInput): string | null {
  const statePath = getStatePath(input.session_id);
  const state = loadState(statePath);

  const name = basename(input.file_path);
  if (!state.files.includes(name)) state.files.push(name);

  const loadedNames = new Set(state.files);
  const projectDir = getProjectDir();
  const missing: string[] = [];

  for (const signal of buildSignals(projectDir)) {
    try {
      if (signal.check() && !loadedNames.has(signal.ruleName)) {
        missing.push(`${signal.ruleName} — ${signal.description}`);
      }
    } catch {
      // Skip failing checks
    }
  }

  state.suggestions = missing;

  let message: string | null = null;
  if (missing.length > 0 && !state.notified) {
    state.notified = true;
    logHook(HOOK_NAME, `Smart suggestions: ${missing.length} rules could be added`);
    const top = missing.slice(0, 3);
    message = `[Rule Suggestions] Consider creating these .claude/rules/ files:\n${top.map(m => `  - ${m}`).join('\n')}`;
  }

  try {
    atomicWriteSync(statePath, JSON.stringify(state, null, 2));
  } catch (err) {
    logHook(HOOK_NAME, `Failed to save loaded-instructions state: ${err}`, 'warn');
  }

  return message;
}
